import { format } from 'date-fns'
import { SearchColumn } from './SearchColumn'

export const COLUMNS = [
    {
        Header: 'ID',
        Footer: 'ID',
        accessor: 'id',
        Filter: SearchColumn
    },
    {
        Header: 'Student ID',
        Footer: 'Student ID',
        accessor: 'studentID',
        Filter: SearchColumn
    },
    {
        Header: 'Name',
        Footer: 'Name',
        accessor: 'name',
        Filter: SearchColumn
    },
    {
        Header: 'Password',
        Footer: 'Password',
        accessor: 'password',
        Filter: SearchColumn
    },
    {
        Header: 'Date Created',
        Footer: 'Date Created',
        accessor: 'dateCreated',
        Cell: ({ value }) => {return format(new Date(value), 'dd/MM/yyyy')},
        Filter: SearchColumn
    }
]
